class Solution:
    def minimumSum(self, n: int, k: int) -> int:
        # Set to keep track of used numbers
        used = set()
        # Result array
        res = []
        # Start from 1 and try to add numbers
        i = 1
        while len(res) < n:
            valid = True
            for num in res:
                if (num + i) == k:
                    valid = False
                    break
            if valid and i not in used:
                res.append(i)
                used.add(i)
            i += 1
        return sum(res)
